import copy
import csv
import io
import json
import threading
from dataclasses import dataclass
from datetime import datetime
from enum import Enum
from typing import Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------

class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class TeamCollaborationError(Exception):
    pass

class ValidationError(TeamCollaborationError):
    pass

class NotFoundError(TeamCollaborationError):
    pass

class AuthorizationError(TeamCollaborationError):
    pass

class DuplicateError(TeamCollaborationError):
    pass

class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Data models  (mutable plain dataclasses - NOT frozen)
# ---------------------------------------------------------------------------

@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: list
    created_at: datetime
    edited_at: Optional[datetime]


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------

class _IDCounter:
    __slots__ = ("_next",)

    def __init__(self):
        self._next = 1

    def alloc(self):
        val = self._next
        self._next += 1
        return val


def _to_json_safe(obj):
    """Recursively make an object JSON-serialisable (handles datetime/Enum/int keys)."""
    if isinstance(obj, dict):
        return {
            (str(k) if not isinstance(k, str) else k): _to_json_safe(v)
            for k, v in obj.items()
        }
    if isinstance(obj, list):
        return [_to_json_safe(i) for i in obj]
    if isinstance(obj, datetime):
        return obj.isoformat()
    if isinstance(obj, Enum):
        return obj.value
    return obj


def _serialize_cell(v):
    """Serialize a single report value to a CSV cell string."""
    if v is None:
        return ""
    if isinstance(v, datetime):
        return v.isoformat()
    if isinstance(v, Enum):
        return v.value
    if isinstance(v, (dict, list)):
        return json.dumps(_to_json_safe(v))
    return str(v)


# ---------------------------------------------------------------------------
# Sub-stores  (pure data containers; all logic lives in TeamCollaborationManager)
# ---------------------------------------------------------------------------

class _UserStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._data = {}         # id -> User
        self._by_username = {}  # username -> id
        self._by_email = {}     # email -> id


class _ProjectStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._data = {}         # id -> Project


class _TaskStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._data = {}         # id -> Task
        self._by_project = {}   # project_id -> set[task_id]
        self._by_assignee = {}  # user_id -> set[task_id]


class _MessageStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._data = {}         # id -> Message
        self._by_project = {}   # project_id -> set[msg_id]
        self._by_task = {}      # task_id -> set[msg_id]


class _PerformanceStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._ratings = {}      # id -> Rating
        self._by_ratee = {}     # user_id -> list[rating_id]


class _ReportStore:
    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# TeamCollaborationManager
# ---------------------------------------------------------------------------

class TeamCollaborationManager:

    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        _ctr = _IDCounter()
        self.users = _UserStore(self._lock, _ctr)
        self.projects = _ProjectStore(self._lock, _ctr)
        self.tasks = _TaskStore(self._lock, _ctr)
        self.messages = _MessageStore(self._lock, _ctr)
        self.performance = _PerformanceStore(self._lock, _ctr)
        self.reports = _ReportStore(self._lock)
        self._counter = _ctr

    # ------------------------------------------------------------------ users

    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not isinstance(username, str):
                raise ValidationError("username must be a string")
            if not isinstance(email, str):
                raise ValidationError("email must be a string")
            if not (username and username.strip()):
                raise ValidationError("username must be non-empty")
            if not (email and "@" in email):
                raise ValidationError("email must contain @")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")
            if username in self.users._by_username:
                raise DuplicateError("username already taken")
            if email in self.users._by_email:
                raise DuplicateError("email already taken")
            uid = self._counter.alloc()
            user = User(uid, username, email, role, self._now())
            self.users._data[uid] = user
            self.users._by_username[username] = uid
            self.users._by_email[email] = uid
            return copy.deepcopy(user)

    def get_user(self, id):
        with self._lock:
            if id not in self.users._data:
                raise NotFoundError("user not found")
            return copy.deepcopy(self.users._data[id])

    def list_users(self):
        with self._lock:
            return [
                copy.deepcopy(u)
                for u in sorted(self.users._data.values(), key=lambda x: x.id)
            ]

    def update_user(self, id, username=None, email=None, role=None):
        with self._lock:
            if id not in self.users._data:
                raise NotFoundError("user not found")
            user = self.users._data[id]
            # Validate first, then apply
            if username is not None:
                if not isinstance(username, str):
                    raise ValidationError("username must be a string")
                if not username.strip():
                    raise ValidationError("username must be non-empty")
                if username != user.username and username in self.users._by_username:
                    raise DuplicateError("username already taken")
            if email is not None:
                if not isinstance(email, str):
                    raise ValidationError("email must be a string")
                if not (email and "@" in email):
                    raise ValidationError("email must contain @")
                if email != user.email and email in self.users._by_email:
                    raise DuplicateError("email already taken")
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole instance")
            # Apply changes
            if username is not None and username != user.username:
                del self.users._by_username[user.username]
                user.username = username
                self.users._by_username[username] = id
            if email is not None and email != user.email:
                del self.users._by_email[user.email]
                user.email = email
                self.users._by_email[email] = id
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, id):
        with self._lock:
            if id not in self.users._data:
                raise NotFoundError("user not found")
            for p in self.projects._data.values():
                if p.owner_id == id:
                    raise ConflictError("user owns a project")
            for tid in self.tasks._by_assignee.get(id, set()):
                t = self.tasks._data.get(tid)
                if t and t.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks")
            # Clear assignee_id on completed tasks so no task references a deleted user
            for tid in list(self.tasks._by_assignee.get(id, set())):
                t = self.tasks._data.get(tid)
                if t:
                    t.assignee_id = None
            user = self.users._data.pop(id)
            del self.users._by_username[user.username]
            del self.users._by_email[user.email]
            self.tasks._by_assignee.pop(id, None)

    # --------------------------------------------------------------- projects

    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if owner_id not in self.users._data:
                raise NotFoundError("owner not found")
            if not (name and name.strip()):
                raise ValidationError("name must be non-empty")
            if not isinstance(start_date, datetime):
                raise ValidationError("start_date must be a datetime")
            if not isinstance(end_date, datetime):
                raise ValidationError("end_date must be a datetime")
            if end_date < start_date:
                raise ValidationError("end_date must be >= start_date")
            pid = self._counter.alloc()
            project = Project(pid, name, description, start_date, end_date, owner_id)
            self.projects._data[pid] = project
            return copy.deepcopy(project)

    def get_project(self, id):
        with self._lock:
            if id not in self.projects._data:
                raise NotFoundError("project not found")
            return copy.deepcopy(self.projects._data[id])

    def list_projects(self):
        with self._lock:
            return [
                copy.deepcopy(p)
                for p in sorted(self.projects._data.values(), key=lambda x: x.id)
            ]

    def update_project(self, id, name=None, start_date=None, end_date=None, description=None):
        with self._lock:
            if id not in self.projects._data:
                raise NotFoundError("project not found")
            project = self.projects._data[id]
            if name is not None and not name.strip():
                raise ValidationError("name must be non-empty")
            if start_date is not None and not isinstance(start_date, datetime):
                raise ValidationError("start_date must be a datetime")
            if end_date is not None and not isinstance(end_date, datetime):
                raise ValidationError("end_date must be a datetime")
            eff_start = start_date if start_date is not None else project.start_date
            eff_end = end_date if end_date is not None else project.end_date
            if eff_end < eff_start:
                raise ValidationError("end_date must be >= start_date")
            # Guard: moving start_date forward must not invalidate existing task deadlines
            if start_date is not None and start_date > project.start_date:
                for tid in self.tasks._by_project.get(id, set()):
                    t = self.tasks._data[tid]
                    if t.deadline is not None and t.deadline < start_date:
                        raise ValidationError(
                            "new start_date would make existing task deadlines invalid"
                        )
            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, id):
        with self._lock:
            if id not in self.projects._data:
                raise NotFoundError("project not found")
            task_ids = set(self.tasks._by_project.get(id, set()))
            # Collect all messages to delete (project-level + task-level)
            msgs_to_delete = set(self.messages._by_project.get(id, set()))
            for tid in task_ids:
                msgs_to_delete.update(self.messages._by_task.get(tid, set()))
            # Remove messages
            for mid in msgs_to_delete:
                if mid in self.messages._data:
                    msg = self.messages._data.pop(mid)
                    if msg.project_id is not None:
                        self.messages._by_project.get(msg.project_id, set()).discard(mid)
                    if msg.task_id is not None:
                        self.messages._by_task.get(msg.task_id, set()).discard(mid)
            self.messages._by_project.pop(id, None)
            for tid in task_ids:
                self.messages._by_task.pop(tid, None)
            # Remove tasks and clean assignee index
            for tid in task_ids:
                t = self.tasks._data.pop(tid, None)
                if t and t.assignee_id is not None:
                    self.tasks._by_assignee.get(t.assignee_id, set()).discard(tid)
            self.tasks._by_project.pop(id, None)
            # Remove project
            del self.projects._data[id]

    # ------------------------------------------------------------------ tasks

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            if project_id not in self.projects._data:
                raise NotFoundError("project not found")
            if not (title and title.strip()):
                raise ValidationError("title must be non-empty")
            if assignee_id is not None and assignee_id not in self.users._data:
                raise NotFoundError("assignee not found")
            project = self.projects._data[project_id]
            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                if deadline < project.start_date:
                    raise ValidationError("deadline is before project start date")
            tid = self._counter.alloc()
            task = Task(
                tid, project_id, title, TaskStatus.NOT_STARTED,
                assignee_id, deadline, None, None, self._now()
            )
            self.tasks._data[tid] = task
            self.tasks._by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self.tasks._by_assignee.setdefault(assignee_id, set()).add(tid)
            return copy.deepcopy(task)

    def get_task(self, id):
        with self._lock:
            if id not in self.tasks._data:
                raise NotFoundError("task not found")
            return copy.deepcopy(self.tasks._data[id])

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects._data:
                raise NotFoundError("project not found")
            tids = self.tasks._by_project.get(project_id, set())
            return [copy.deepcopy(self.tasks._data[tid]) for tid in sorted(tids)]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            if user_id not in self.users._data:
                raise NotFoundError("user not found")
            tids = self.tasks._by_assignee.get(user_id, set())
            return [copy.deepcopy(self.tasks._data[tid]) for tid in sorted(tids)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            if assignee_id not in self.users._data:
                raise NotFoundError("assignee not found")
            task = self.tasks._data[task_id]
            if task.assignee_id is not None:
                self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = assignee_id
            self.tasks._by_assignee.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            if task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            if new_assignee_id not in self.users._data:
                raise NotFoundError("new assignee not found")
            task = self.tasks._data[task_id]
            if task.assignee_id is not None:
                self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = new_assignee_id
            self.tasks._by_assignee.setdefault(new_assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            task = self.tasks._data[task_id]
            if task.assignee_id is not None:
                self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            if task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            task = self.tasks._data[task_id]
            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                project = self.projects._data[task.project_id]
                if deadline < project.start_date:
                    raise ValidationError("deadline is before project start date")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            if task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            task = self.tasks._data[task_id]
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                task.status = TaskStatus.IN_PROGRESS
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                task.status = TaskStatus.COMPLETED
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.status = TaskStatus.NOT_STARTED
                task.started_at = None
                task.completed_at = None
            return copy.deepcopy(task)

    # --------------------------------------------------------------- messages

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            if author_id not in self.users._data:
                raise NotFoundError("author not found")
            # Exactly one of project_id / task_id must be set
            if (project_id is None) == (task_id is None):
                raise ValidationError("exactly one of project_id or task_id must be set")
            if project_id is not None and project_id not in self.projects._data:
                raise NotFoundError("project not found")
            if task_id is not None and task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            if not isinstance(body, str):
                raise ValidationError("body must be a string")
            if not body.strip() and not attachments:
                raise ValidationError("body must be non-empty when no attachments")
            if parent_id is not None and parent_id not in self.messages._data:
                raise NotFoundError("parent message not found")
            att_list = []
            if attachments:
                for fname, data in attachments:
                    att_list.append(Attachment(fname, len(data), author_id, self._now()))
            mid = self._counter.alloc()
            msg = Message(
                mid, author_id, body, project_id, task_id, parent_id,
                att_list, self._now(), None
            )
            self.messages._data[mid] = msg
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, set()).add(mid)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, set()).add(mid)
            return copy.deepcopy(msg)

    def edit_message(self, msg_id, editor_id, new_body):
        with self._lock:
            if msg_id not in self.messages._data:
                raise NotFoundError("message not found")
            if editor_id not in self.users._data:
                raise NotFoundError("editor not found")
            msg = self.messages._data[msg_id]
            if msg.author_id != editor_id:
                raise AuthorizationError("only the author can edit this message")
            if not isinstance(new_body, str):
                raise ValidationError("body must be a string")
            if not new_body.strip() and not msg.attachments:
                raise ValidationError("body must be non-empty when no attachments")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, msg_id, uploader_id, filename, data):
        with self._lock:
            if msg_id not in self.messages._data:
                raise NotFoundError("message not found")
            if uploader_id not in self.users._data:
                raise NotFoundError("uploader not found")
            msg = self.messages._data[msg_id]
            if msg.author_id != uploader_id:
                raise AuthorizationError("only the author can add attachments")
            if not isinstance(filename, str):
                raise ValidationError("filename must be a string")
            if not filename:
                raise ValidationError("filename must be non-empty")
            msg.attachments.append(Attachment(filename, len(data), uploader_id, self._now()))
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects._data:
                raise NotFoundError("project not found")
            mids = self.messages._by_project.get(project_id, set())
            return [copy.deepcopy(self.messages._data[mid]) for mid in sorted(mids)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            mids = self.messages._by_task.get(task_id, set())
            return [copy.deepcopy(self.messages._data[mid]) for mid in sorted(mids)]

    def delete_message(self, msg_id, requester_id):
        with self._lock:
            if msg_id not in self.messages._data:
                raise NotFoundError("message not found")
            if requester_id not in self.users._data:
                raise NotFoundError("requester not found")
            msg = self.messages._data[msg_id]
            if msg.author_id != requester_id:
                raise AuthorizationError("only the author can delete this message")
            if msg.project_id is not None:
                self.messages._by_project.get(msg.project_id, set()).discard(msg_id)
            if msg.task_id is not None:
                self.messages._by_task.get(msg.task_id, set()).discard(msg_id)
            del self.messages._data[msg_id]

    # ------------------------------------------------------------ performance

    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self.users._data:
                raise NotFoundError("user not found")
            tids = self.tasks._by_assignee.get(user_id, set())
            total = len(tids)
            if total == 0:
                return 0.0
            completed = sum(
                1 for tid in tids
                if self.tasks._data[tid].status == TaskStatus.COMPLETED
            )
            return completed / total

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self.users._data:
                raise NotFoundError("user not found")
            tids = self.tasks._by_assignee.get(user_id, set())
            times = []
            for tid in tids:
                t = self.tasks._data[tid]
                if (t.status == TaskStatus.COMPLETED
                        and t.started_at is not None
                        and t.completed_at is not None):
                    times.append(max(0.0, (t.completed_at - t.started_at).total_seconds()))
            return sum(times) / len(times) if times else None

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id not in self.users._data:
                raise NotFoundError("rater not found")
            if ratee_id not in self.users._data:
                raise NotFoundError("ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if not (1 <= score <= 5):
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None and task_id not in self.tasks._data:
                raise NotFoundError("task not found")
            rid = self._counter.alloc()
            rating = Rating(rid, rater_id, ratee_id, score, feedback, task_id, self._now())
            self.performance._ratings[rid] = rating
            self.performance._by_ratee.setdefault(ratee_id, []).append(rid)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self.users._data:
                raise NotFoundError("user not found")
            rids = self.performance._by_ratee.get(user_id, [])
            ratings = [copy.deepcopy(self.performance._ratings[rid]) for rid in rids]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count > 0 else 0.0
            return {"count": count, "average": average, "ratings": ratings}

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self.users._data:
                raise NotFoundError("user not found")
            tids = self.tasks._by_assignee.get(user_id, set())
            total = len(tids)
            completed = in_progress = not_started = 0
            times = []
            for tid in tids:
                t = self.tasks._data[tid]
                if t.status == TaskStatus.COMPLETED:
                    completed += 1
                    if t.started_at and t.completed_at:
                        times.append(max(0.0, (t.completed_at - t.started_at).total_seconds()))
                elif t.status == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                else:
                    not_started += 1
            completion_rate = completed / total if total > 0 else 0.0
            avg_time = sum(times) / len(times) if times else None
            rids = self.performance._by_ratee.get(user_id, [])
            rating_count = len(rids)
            rating_avg = (
                sum(self.performance._ratings[r].score for r in rids) / rating_count
                if rating_count > 0 else 0.0
            )
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_avg,
            }

    # ---------------------------------------------------------------- reports

    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self.projects._data:
                raise NotFoundError("project not found")
            tids = self.tasks._by_project.get(project_id, set())
            total = len(tids)
            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            now = self._now()
            overdue = 0
            per_assignee = {}
            for tid in tids:
                t = self.tasks._data[tid]
                status_counts[t.status.value] += 1
                if (t.deadline is not None
                        and t.deadline < now
                        and t.status != TaskStatus.COMPLETED):
                    overdue += 1
                if t.assignee_id is not None:
                    aid = t.assignee_id
                    if aid not in per_assignee:
                        per_assignee[aid] = {
                            "total": 0, "completed": 0,
                            "in_progress": 0, "not_started": 0,
                        }
                    per_assignee[aid]["total"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        per_assignee[aid]["completed"] += 1
                    elif t.status == TaskStatus.IN_PROGRESS:
                        per_assignee[aid]["in_progress"] += 1
                    else:
                        per_assignee[aid]["not_started"] += 1
            completed_count = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed_count / total if total > 0 else 0.0
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self.projects._data:
                raise NotFoundError("project not found")
            if project_id is not None:
                scoped_tids = set(self.tasks._by_project.get(project_id, set()))
            else:
                scoped_tids = set(self.tasks._data.keys())
            # Unique assignees within scope
            assignees = {
                self.tasks._data[tid].assignee_id
                for tid in scoped_tids
                if self.tasks._data[tid].assignee_id is not None
            }
            rows = []
            for uid in assignees:
                if project_id is not None:
                    user_tids = {
                        tid for tid in scoped_tids
                        if self.tasks._data[tid].assignee_id == uid
                    }
                else:
                    user_tids = self.tasks._by_assignee.get(uid, set())
                total = len(user_tids)
                completed = 0
                times = []
                for tid in user_tids:
                    t = self.tasks._data[tid]
                    if t.status == TaskStatus.COMPLETED:
                        completed += 1
                        if t.started_at and t.completed_at:
                            times.append(max(0.0, (t.completed_at - t.started_at).total_seconds()))
                rate = completed / total if total > 0 else 0.0
                avg_time = sum(times) / len(times) if times else None
                rids = self.performance._by_ratee.get(uid, [])
                rc = len(rids)
                ra = (
                    sum(self.performance._ratings[r].score for r in rids) / rc
                    if rc > 0 else 0.0
                )
                rows.append({
                    "user_id": uid,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": rate,
                    "average_completion_time": avg_time,
                    "rating_count": rc,
                    "rating_average": ra,
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self.users._data:
                raise NotFoundError("user not found")
            tids = self.tasks._by_assignee.get(user_id, set())
            total = len(tids)
            completed = 0
            times = []
            task_list = []
            for tid in sorted(tids):
                t = self.tasks._data[tid]
                if t.status == TaskStatus.COMPLETED:
                    completed += 1
                    if t.started_at and t.completed_at:
                        times.append(max(0.0, (t.completed_at - t.started_at).total_seconds()))
                task_list.append({
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline.isoformat() if t.deadline else None,
                    "started_at": t.started_at.isoformat() if t.started_at else None,
                    "completed_at": t.completed_at.isoformat() if t.completed_at else None,
                })
            rate = completed / total if total > 0 else 0.0
            avg_time = sum(times) / len(times) if times else None
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": rate,
                "average_completion_time": avg_time,
                "tasks": task_list,
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat instance")
            if fmt == ReportFormat.CSV:
                return self._export_csv(report)
            return self._export_pdf(report)

    # -------------------------------------------------------- export helpers

    def _export_csv(self, report):
        buf = io.StringIO()
        writer = csv.writer(buf)
        scalar_keys = [k for k in report if k != "rows"]
        writer.writerow(scalar_keys)
        writer.writerow([_serialize_cell(report[k]) for k in scalar_keys])
        rows = report.get("rows") or []
        if rows:
            row_keys = list(rows[0].keys())
            writer.writerow(row_keys)
            for row in rows:
                writer.writerow([_serialize_cell(row[k]) for k in row_keys])
        return buf.getvalue()

    def _export_pdf(self, report):
        # Build a minimal but spec-valid PDF embedding a text summary of the report.
        summary = {}
        for k, v in report.items():
            if k != "rows":
                summary[k] = _serialize_cell(v)
            else:
                summary[k] = "[{0} rows]".format(len(v)) if v else "[]"
        text = json.dumps(summary, indent=2, ensure_ascii=True)

        # Build PDF content stream
        stream_lines = ["BT", "/F1 10 Tf", "50 750 Td"]
        for raw_line in text.splitlines()[:50]:
            safe = (raw_line
                    .replace("\\", "\\\\")
                    .replace("(", "\\(")
                    .replace(")", "\\)"))
            stream_lines.append("({0}) Tj".format(safe))
            stream_lines.append("0 -14 Td")
        stream_lines.append("ET")
        stream_content = "\n".join(stream_lines).encode("latin-1")
        stream_len = len(stream_content)

        parts = []

        def emit(data: bytes):
            parts.append(data)

        offsets = []

        def write_obj(num, header, stream=None):
            offsets.append(sum(len(p) for p in parts))
            emit("{0} 0 obj\n{1}\n".format(num, header).encode("latin-1"))
            if stream is not None:
                emit(b"stream\n")
                emit(stream)
                emit(b"\nendstream\n")
            emit(b"endobj\n")

        emit(b"%PDF-1.4\n")
        write_obj(1, "<< /Type /Catalog /Pages 2 0 R >>")
        write_obj(2, "<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
        write_obj(
            3,
            "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792]"
            " /Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        )
        write_obj(4, "<< /Length {0} >>".format(stream_len), stream_content)
        write_obj(5, "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>")

        xref_offset = sum(len(p) for p in parts)
        xref = "xref\n0 6\n0000000000 65535 f \n"
        for off in offsets:
            xref += "{0:010d} 00000 n \n".format(off)
        emit(xref.encode("latin-1"))
        trailer = (
            "trailer\n<< /Size 6 /Root 1 0 R >>\n"
            "startxref\n{0}\n%%EOF\n".format(xref_offset)
        )
        emit(trailer.encode("latin-1"))

        return b"".join(parts)
